import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"流星","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/流星.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/流星.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/流星.md"};function l(i,a,p,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"流星",tabindex:"-1"},[s("流星 "),e("a",{class:"header-anchor",href:"#流星","aria-label":'Permalink to "流星"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),o('<h1 id="流星-1" tabindex="-1">流星 <a class="header-anchor" href="#流星-1" aria-label="Permalink to &quot;流星&quot;">​</a></h1><p>流星<br> 价格：A+5000<br> 分类：长枪<br> 武器伤害：27L<br> 武器特性：【长柄】【双手】【湮灭】【格挡2】【攻击额外获得2个附加成功数】<br> 武器体积：4<br> 伤害类型：物理-穿刺<br> 描述：据说以状绝速度贯穿坚硬铠甲的长枪，其攻势宛若流星般令人难以招架；此外，枪的魔力能促进魔力循环、提高运行效率。<br> 效果：持有该武器进行攻击时，附带A级措手不及效果，并无视盔甲防御（视为A级创伤来源的效果）；持有者在消耗魔力时，消耗的魔力减少【传奇沉着】*1点（下限1），每轮仅生效一次。</p><p>当持有者在一次攻击中消耗了至少1点魔力时，本次攻击中每消耗了1点魔力（也计入减少消耗的部分）就会额外获得5点威猛，最多获得等同【传奇敏捷】*5点【威猛】，在处理目标防御后若因此获得的【威猛】仍有剩余，则这些剩余威猛以3：1的比例转为攻击检定上的额外附加成功数，这些威猛最多转化【传奇敏捷】+【传奇力量】个附加成功数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
